import { Clock, DomainEventPublisher, err, ok } from "../../../shared-kernel";
import { LibraryError } from "../../domain";
import { LibraryApplicationError } from "../errors";
import {
  UpdateCollection,
  UpdateCollectionCommand,
} from "../ports/in/update-collection.port";
import { CollectionRepository } from "../ports/out/collection.repository";

export interface UpdateCollectionDeps {
  readonly collections: CollectionRepository;
  readonly events: DomainEventPublisher;
  readonly clock: Clock;
}

// Transaction script: load (→ CollectionNotFound), require ownership, and — only when the name
// actually changes — enforce (owner, name) uniqueness via the repository before delegating the
// patch to the aggregate. Uniqueness needs the repository, so it lives here, mirroring
// CreateCollection; the aggregate records CollectionUpdated.
export const makeUpdateCollection =
  (deps: UpdateCollectionDeps): UpdateCollection =>
  async (cmd: UpdateCollectionCommand) => {
    const collection = await deps.collections.findById(cmd.collectionId);
    if (!collection)
      return err(LibraryApplicationError.collectionNotFound(cmd.collectionId));
    if (collection.ownerId !== cmd.actingMemberId) {
      return err(LibraryError.notOwner("update this collection"));
    }

    if (cmd.name !== undefined && cmd.name !== collection.name) {
      const existing = await deps.collections.findByOwnerAndName(
        collection.ownerId,
        cmd.name,
      );
      if (existing && existing.id !== collection.id) {
        return err(LibraryApplicationError.duplicateCollectionName(cmd.name));
      }
    }

    const outcome = collection.update(
      {
        name: cmd.name,
        description: cmd.description,
        visibility: cmd.visibility,
        color: cmd.color,
        icon: cmd.icon,
        personalNotes: cmd.personalNotes,
      },
      deps.clock.now(),
    );
    if (outcome.isErr) return err(outcome.error);

    await deps.collections.save(collection);
    await deps.events.publish(collection.pullEvents());
    return ok(undefined);
  };

import { Clock, DomainEventPublisher, err, ok } from "../../../shared-kernel";
import { LibraryError } from "../../domain";
import { LibraryApplicationError } from "../errors";
import {
  UpdateCopyDetails,
  UpdateCopyDetailsCommand,
} from "../ports/in/update-copy-details.port";
import { CopyRepository } from "../ports/out/copy.repository";

export interface UpdateCopyDetailsDeps {
  readonly copies: CopyRepository;
  readonly events: DomainEventPublisher;
  readonly clock: Clock;
}

// Transaction script: load (→ CopyNotFound), check ownership, delegate the descriptive-field
// patch (missing-piece count, notes) to the aggregate, persist, publish.
export const makeUpdateCopyDetails =
  (deps: UpdateCopyDetailsDeps): UpdateCopyDetails =>
  async (cmd: UpdateCopyDetailsCommand) => {
    const copy = await deps.copies.findById(cmd.copyId);
    if (!copy) return err(LibraryApplicationError.copyNotFound(cmd.copyId));
    if (copy.ownerId !== cmd.actingMemberId) {
      return err(LibraryError.notOwner("update this copy's details"));
    }

    const outcome = copy.updateDetails(
      {
        missingPiecesCount: cmd.missingPiecesCount,
        notes: cmd.notes,
      },
      deps.clock.now(),
    );
    if (outcome.isErr) return err(outcome.error);

    await deps.copies.save(copy);
    await deps.events.publish(copy.pullEvents());
    return ok(undefined);
  };

import { Clock, DomainEventPublisher, err, ok } from "../../../shared-kernel";
import { LibraryError, SharingSetting } from "../../domain";
import { LibraryApplicationError } from "../errors";
import {
  UpdateCopySharing,
  UpdateCopySharingCommand,
} from "../ports/in/update-copy-sharing.port";
import { CopyReservationPort } from "../ports/out/copy-reservation.port";
import { CopyRepository } from "../ports/out/copy.repository";

export interface UpdateCopySharingDeps {
  readonly copies: CopyRepository;
  // The seam to Exchange: enforces "cannot make available while reserved by an active Exchange".
  readonly reservations: CopyReservationPort;
  readonly events: DomainEventPublisher;
  readonly clock: Clock;
}

// Transaction script: load (→ CopyNotFound), check ownership, and — only when the new setting
// offers the copy for exchange — consult the reservation seam before letting the aggregate
// update its sharing. The "reserved by an active Exchange" rule is APPLICATION-level (it needs
// Exchange state), so it lives here, not in the Copy aggregate.
export const makeUpdateCopySharing =
  (deps: UpdateCopySharingDeps): UpdateCopySharing =>
  async (cmd: UpdateCopySharingCommand) => {
    const copy = await deps.copies.findById(cmd.copyId);
    if (!copy) return err(LibraryApplicationError.copyNotFound(cmd.copyId));
    if (copy.ownerId !== cmd.actingMemberId) {
      return err(LibraryError.notOwner("update this copy's sharing"));
    }

    const setting = SharingSetting.create({
      visibility: cmd.visibility,
      forTrade: cmd.forTrade,
      forSale: cmd.forSale,
      forLend: cmd.forLend,
      salePrice: cmd.salePrice,
    });

    if (
      setting.isAvailableForAnyExchange() &&
      (await deps.reservations.isReserved(cmd.copyId))
    ) {
      return err(LibraryApplicationError.copyReserved(cmd.copyId));
    }

    const outcome = copy.updateSharing(setting, deps.clock.now());
    if (outcome.isErr) return err(outcome.error);

    await deps.copies.save(copy);
    await deps.events.publish(copy.pullEvents());
    return ok(undefined);
  };

