import { DomainEvent } from "../../shared-kernel";
import { ReputationChanged } from "./events";
import { MemberId, ReputationProfileId } from "./ids";
import { PartnerReview } from "./partner-review";

// The persistable shape of a member's aggregated reputation. We keep the running `ratingSum`
// and `reviewCount` (rather than only the average) so applyReview recomputes exactly without
// reloading every PartnerReview, and so the stored average is always derivable. `credibility`
// is a 0-1 confidence that grows with the number of reviews (a simple, deterministic curve).
export interface ReputationProfileState {
  readonly id: ReputationProfileId;
  readonly memberId: MemberId;
  readonly ratingSum: number;
  readonly reviewCount: number;
  readonly averageRating: number;
  readonly credibility: number;
  readonly updatedAt: Date;
}

// Number of reviews at which credibility is considered fully established.
const CREDIBILITY_SATURATION = 10;

// ReputationProfile: the per-member aggregate root. It consumes PartnerReviews (received as
// the reviewee) and maintains the aggregate score + count + credibility. Recomputing on each
// applied review keeps the average authoritative and emits ReputationChanged.
export class ReputationProfile {
  private events: DomainEvent[] = [];

  private constructor(private state: ReputationProfileState) {}

  get id(): ReputationProfileId {
    return this.state.id;
  }

  get memberId(): MemberId {
    return this.state.memberId;
  }

  get averageRating(): number {
    return this.state.averageRating;
  }

  get reviewCount(): number {
    return this.state.reviewCount;
  }

  get credibility(): number {
    return this.state.credibility;
  }

  // A fresh, empty profile for a member who has not yet been reviewed.
  static open(
    id: ReputationProfileId,
    memberId: MemberId,
    now: Date,
  ): ReputationProfile {
    return new ReputationProfile({
      id,
      memberId,
      ratingSum: 0,
      reviewCount: 0,
      averageRating: 0,
      credibility: 0,
      updatedAt: now,
    });
  }

  // Fold a received review into the aggregate: add its overall rating to the running sum,
  // bump the count, recompute the average and credibility, then emit ReputationChanged. The
  // review must be ABOUT this member (revieweeId === memberId); the application layer loads
  // the reviewee's profile, so this is an invariant the caller upholds.
  applyReview(review: PartnerReview, now: Date): void {
    const ratingSum = this.state.ratingSum + review.rating.value;
    const reviewCount = this.state.reviewCount + 1;
    const averageRating = ratingSum / reviewCount;
    const credibility = Math.min(reviewCount / CREDIBILITY_SATURATION, 1);

    this.state = {
      ...this.state,
      ratingSum,
      reviewCount,
      averageRating,
      credibility,
      updatedAt: now,
    };

    this.record(
      new ReputationChanged(
        this.state.memberId,
        averageRating,
        reviewCount,
        now,
      ),
    );
  }

  // Drain recorded events for the publisher; clears the buffer so a save can't double-emit.
  pullEvents(): readonly DomainEvent[] {
    const drained = this.events;
    this.events = [];
    return drained;
  }

  // Map to/from persistence without the aggregate knowing about any storage technology.
  static rehydrate(state: ReputationProfileState): ReputationProfile {
    return new ReputationProfile(state);
  }

  toState(): ReputationProfileState {
    return this.state;
  }

  private record(event: DomainEvent): void {
    this.events.push(event);
  }
}

src/reputation/domain/review-scores.ts.source:
import { err, ok, Result } from "../../shared-kernel";
import { ReputationError } from "./errors";
import { StarRating } from "./star-rating";

// The four sub-scores carried by a PartnerReview, matching the `reviews.categories` column
// (communication, packaging, condition, timeliness). Each is a validated 1-5 StarRating.
export interface PartnerReviewScoresInput {
  readonly communication: number;
  readonly packaging: number;
  readonly condition: number;
  readonly timeliness: number;
}

// Immutable value object grouping the four category sub-scores. Constructed only via
// `create`, which validates every sub-score; an invalid one fails the whole VO.
export class PartnerReviewScores {
  private constructor(
    readonly communication: StarRating,
    readonly packaging: StarRating,
    readonly condition: StarRating,
    readonly timeliness: StarRating,
  ) {}

  static create(
    input: PartnerReviewScoresInput,
  ): Result<PartnerReviewScores, ReputationError> {
    const communication = StarRating.create(input.communication);
    if (communication.isErr) return err(communication.error);
    const packaging = StarRating.create(input.packaging);
    if (packaging.isErr) return err(packaging.error);
    const condition = StarRating.create(input.condition);
    if (condition.isErr) return err(condition.error);
    const timeliness = StarRating.create(input.timeliness);
    if (timeliness.isErr) return err(timeliness.error);

    return ok(
      new PartnerReviewScores(
        communication.value,
        packaging.value,
        condition.value,
        timeliness.value,
      ),
    );
  }
}

src/reputation/domain/star-rating.ts.source:
import { err, ok, Result } from "../../shared-kernel";
import { ReputationError } from "./errors";

// A 1-5 star rating as an immutable value object validated at construction. Only integers in
// the inclusive [1, 5] range are valid; 0 and 6 (and fractional values) are rejected with
// InvalidRating. (Solving will declare its own StarRating locally; barrel disambiguation
// handles the name at integration.)
export class StarRating {
  private constructor(readonly value: number) {}

  static create(value: number): Result<StarRating, ReputationError> {
    if (!Number.isInteger(value) || value < 1 || value > 5) {
      return err(ReputationError.invalidRating(value));
    }
    return ok(new StarRating(value));
  }
}

