import { beforeEach, describe, expect, it } from "vitest";
import { toCopyId, toExchangeId, toMemberId } from "../../../shared-kernel";
import { Exchange } from "../../domain";
import {
  FixedClock,
  InMemoryExchangeRepository,
  RecordingEventPublisher,
} from "../testing";
import { makeAcceptExchange } from "./accept-exchange";
import { makeCancelExchange } from "./cancel-exchange";
import { makeConfirmCompletion } from "./confirm-completion";
import { makeDeclineExchange } from "./decline-exchange";
import { makeRaiseDispute } from "./raise-dispute";

const alice = toMemberId("alice"); // initiator
const bob = toMemberId("bob"); // recipient
const eve = toMemberId("eve"); // outsider
const requestedId = toCopyId("requested");
const exId = toExchangeId("ex-1");
const NOW = new Date("2026-06-08T10:00:00Z");
const LATER = new Date("2026-06-09T10:00:00Z");

// A proposed swap exchange, persisted, ready for a lifecycle action.
const seedProposed = async (
  repo: InMemoryExchangeRepository,
): Promise<void> => {
  const result = Exchange.propose({
    id: exId,
    initiator: alice,
    recipient: bob,
    requestedCopyId: requestedId,
    terms: { kind: "lend", returnDate: LATER },
    now: NOW,
  });
  if (!result.isOk) throw new Error("setup");
  result.value.pullEvents();
  await repo.save(result.value);
};

const seedAccepted = async (
  repo: InMemoryExchangeRepository,
): Promise<void> => {
  await seedProposed(repo);
  const ex = await repo.findById(exId);
  if (!ex) throw new Error("setup");
  ex.accept(bob, NOW);
  ex.pullEvents();
  await repo.save(ex);
};

const harness = () => {
  const repo = new InMemoryExchangeRepository();
  const events = new RecordingEventPublisher();
  const clock = new FixedClock(NOW);
  return { repo, events, clock, exchanges: repo };
};

describe("makeAcceptExchange", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("accepts a proposed exchange, persisting and publishing ExchangeAccepted", async () => {
    await seedProposed(h.repo);
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["ExchangeAccepted"]);
    expect((await h.repo.findById(exId))?.status).toBe("accepted");
  });

  it("returns ExchangeNotFound when no exchange exists", async () => {
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("ExchangeNotFound");
  });

  it("delegates wrong-party rejection to the aggregate", async () => {
    await seedProposed(h.repo);
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("WrongParty");
    expect(h.events.published).toHaveLength(0);
  });

  it("delegates illegal-transition rejection to the aggregate", async () => {
    await seedAccepted(h.repo);
    const result = await makeAcceptExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("IllegalTransition");
  });
});

describe("makeDeclineExchange", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("declines a proposed exchange, publishing ExchangeRejected", async () => {
    await seedProposed(h.repo);
    const result = await makeDeclineExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["ExchangeRejected"]);
    expect((await h.repo.findById(exId))?.status).toBe("rejected");
  });

  it("returns ExchangeNotFound when no exchange exists", async () => {
    const result = await makeDeclineExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("ExchangeNotFound");
  });
});

describe("makeCancelExchange", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("lets the initiator cancel, publishing ExchangeCancelled", async () => {
    await seedProposed(h.repo);
    const result = await makeCancelExchange(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["ExchangeCancelled"]);
    expect((await h.repo.findById(exId))?.status).toBe("cancelled");
  });

  it("delegates wrong-party rejection to the aggregate", async () => {
    await seedProposed(h.repo);
    const result = await makeCancelExchange(h)({
      exchangeId: exId,
      actingMemberId: bob,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("WrongParty");
  });
});

describe("makeRaiseDispute", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("lets a party dispute an accepted exchange, publishing DisputeRaised", async () => {
    await seedAccepted(h.repo);
    const result = await makeRaiseDispute(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isOk).toBe(true);
    expect(h.events.names()).toEqual(["DisputeRaised"]);
    expect((await h.repo.findById(exId))?.status).toBe("disputed");
  });

  it("delegates wrong-party rejection to the aggregate", async () => {
    await seedAccepted(h.repo);
    const result = await makeRaiseDispute(h)({
      exchangeId: exId,
      actingMemberId: eve,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("WrongParty");
  });
});

describe("makeConfirmCompletion (dual confirmation)", () => {
  let h: ReturnType<typeof harness>;
  beforeEach(() => (h = harness()));

  it("first confirmation keeps the exchange accepted and emits no completion events", async () => {
    await seedAccepted(h.repo);
    const result = await makeConfirmCompletion(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isOk).toBe(true);
    expect((await h.repo.findById(exId))?.status).toBe("accepted");
    expect(h.events.published).toHaveLength(0);
  });

  it("second confirmation completes and publishes ExchangeCompleted + PossessionTransferred", async () => {
    await seedAccepted(h.repo);
    const confirm = makeConfirmCompletion(h);

    await confirm({ exchangeId: exId, actingMemberId: alice });
    h.clock.set(LATER); // second confirmation happens later
    const result = await confirm({ exchangeId: exId, actingMemberId: bob });

    expect(result.isOk).toBe(true);
    expect((await h.repo.findById(exId))?.status).toBe("completed");
    // the seeded exchange is a lend → possession (not ownership) of the requested copy moves
    expect(h.events.names()).toEqual([
      "ExchangeCompleted",
      "PossessionTransferred",
    ]);
  });

  it("returns ExchangeNotFound when no exchange exists", async () => {
    const result = await makeConfirmCompletion(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("ExchangeNotFound");
  });

  it("delegates illegal-transition rejection (confirming a proposed exchange)", async () => {
    await seedProposed(h.repo);
    const result = await makeConfirmCompletion(h)({
      exchangeId: exId,
      actingMemberId: alice,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("IllegalTransition");
  });
});

src/exchange/application/use-cases/propo.source:
import { beforeEach, describe, expect, it } from "vitest";
import { toCopyId, toMemberId } from "../../../shared-kernel";
import { ExchangeTermsInput, Money } from "../../domain";
import { CopyView } from "../ports/out/copy.port";
import {
  FakeCopyPort,
  FixedClock,
  InMemoryExchangeRepository,
  RecordingEventPublisher,
  SequentialIdGenerator,
} from "../testing";
import { makeProposeExchange } from "./propose-exchange";

const alice = toMemberId("alice"); // initiator
const bob = toMemberId("bob"); // recipient
const requestedId = toCopyId("requested");
const offeredId = toCopyId("offered");
const NOW = new Date("2026-06-08T10:00:00Z");

const price = (): Money => {
  const m = Money.create(2500, "EUR");
  if (!m.isOk) throw new Error("setup");
  return m.value;
};

// A copy with all availability flags off; tests turn on exactly what they need.
const copy = (
  over: Partial<CopyView> & Pick<CopyView, "id" | "ownerId">,
): CopyView => ({
  availability: { forTrade: false, forSale: false, forLend: false },
  ...over,
});

describe("makeProposeExchange", () => {
  let repo: InMemoryExchangeRepository;
  let copies: FakeCopyPort;
  let events: RecordingEventPublisher;
  let propose: ReturnType<typeof makeProposeExchange>;

  beforeEach(() => {
    repo = new InMemoryExchangeRepository();
    copies = new FakeCopyPort();
    events = new RecordingEventPublisher();
    propose = makeProposeExchange({
      exchanges: repo,
      copies,
      ids: new SequentialIdGenerator(),
      events,
      clock: new FixedClock(NOW),
    });
  });

  const swapTerms: ExchangeTermsInput = {
    kind: "swap",
    offeredCopyId: offeredId,
  };
  const saleTerms = (): ExchangeTermsInput => ({
    kind: "sale",
    price: price(),
  });
  const lendTerms: ExchangeTermsInput = {
    kind: "lend",
    returnDate: new Date("2026-06-20T10:00:00Z"),
  };

  it("proposes a swap, saving state and publishing ExchangeProposed", async () => {
    copies
      .seed(
        copy({
          id: requestedId,
          ownerId: bob,
          availability: { forTrade: true, forSale: false, forLend: false },
        }),
      )
      .seed(copy({ id: offeredId, ownerId: alice }));

    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "swap",
      requestedCopyId: requestedId,
      terms: swapTerms,
    });

    expect(result.isOk).toBe(true);
    expect(repo.size()).toBe(1);
    expect(events.names()).toEqual(["ExchangeProposed"]);
  });

  it("rejects a duplicate active proposal for the same requested copy", async () => {
    copies
      .seed(
        copy({
          id: requestedId,
          ownerId: bob,
          availability: { forTrade: true, forSale: false, forLend: false },
        }),
      )
      .seed(copy({ id: offeredId, ownerId: alice }));
    const cmd = {
      initiatorId: alice,
      recipientId: bob,
      kind: "swap" as const,
      requestedCopyId: requestedId,
      terms: swapTerms,
    };
    expect((await propose(cmd)).isOk).toBe(true);

    const second = await propose(cmd);
    expect(second.isErr).toBe(true);
    if (second.isErr) expect(second.error.code).toBe("DuplicateProposal");
    expect(repo.size()).toBe(1); // no second exchange written
  });

  it("rejects when the requested copy does not exist", async () => {
    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "sale",
      requestedCopyId: requestedId,
      terms: saleTerms(),
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    expect(events.published).toHaveLength(0);
  });

  // The CORRECTED availability direction: available ⇒ ok, unavailable ⇒ reject.
  describe("availability is checked per kind (corrected direction)", () => {
    it.each<["swap" | "sale" | "lend", keyof CopyView["availability"]]>([
      ["swap", "forTrade"],
      ["sale", "forSale"],
      ["lend", "forLend"],
    ])("%s proceeds only when %s is true", async (kind, flag) => {
      const terms: ExchangeTermsInput =
        kind === "swap" ? swapTerms : kind === "sale" ? saleTerms() : lendTerms;

      // available ⇒ ok
      const available = new FakeCopyPort()
        .seed(
          copy({
            id: requestedId,
            ownerId: bob,
            availability: {
              forTrade: false,
              forSale: false,
              forLend: false,
              [flag]: true,
            },
          }),
        )
        .seed(copy({ id: offeredId, ownerId: alice }));
      const okEvents = new RecordingEventPublisher();
      const proposeOk = makeProposeExchange({
        exchanges: new InMemoryExchangeRepository(),
        copies: available,
        ids: new SequentialIdGenerator(),
        events: okEvents,
        clock: new FixedClock(NOW),
      });
      const okRes = await proposeOk({
        initiatorId: alice,
        recipientId: bob,
        kind,
        requestedCopyId: requestedId,
        terms,
      });
      expect(okRes.isOk).toBe(true);
      expect(okEvents.names()).toEqual(["ExchangeProposed"]);

      // unavailable ⇒ reject
      const unavailable = new FakeCopyPort()
        .seed(copy({ id: requestedId, ownerId: bob }))
        .seed(copy({ id: offeredId, ownerId: alice }));
      const proposeReject = makeProposeExchange({
        exchanges: new InMemoryExchangeRepository(),
        copies: unavailable,
        ids: new SequentialIdGenerator(),
        events: new RecordingEventPublisher(),
        clock: new FixedClock(NOW),
      });
      const rejectRes = await proposeReject({
        initiatorId: alice,
        recipientId: bob,
        kind,
        requestedCopyId: requestedId,
        terms,
      });
      expect(rejectRes.isErr).toBe(true);
      if (rejectRes.isErr)
        expect(rejectRes.error.code).toBe("CopyNotAvailable");
    });
  });

  it("rejects a swap whose offered copy is not owned by the initiator", async () => {
    copies
      .seed(
        copy({
          id: requestedId,
          ownerId: bob,
          availability: { forTrade: true, forSale: false, forLend: false },
        }),
      )
      .seed(copy({ id: offeredId, ownerId: bob })); // offered owned by recipient, not initiator

    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "swap",
      requestedCopyId: requestedId,
      terms: swapTerms,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("OfferedCopyNotOwned");
  });

  it("rejects a swap whose offered copy does not exist", async () => {
    copies.seed(
      copy({
        id: requestedId,
        ownerId: bob,
        availability: { forTrade: true, forSale: false, forLend: false },
      }),
    );

    const result = await propose({
      initiatorId: alice,
      recipientId: bob,
      kind: "swap",
      requestedCopyId: requestedId,
      terms: swapTerms,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
  });

  it("delegates self-exchange rejection to the aggregate", async () => {
    copies.seed(
      copy({
        id: requestedId,
        ownerId: alice,
        availability: { forTrade: false, forSale: true, forLend: false },
      }),
    );

    const result = await propose({
      initiatorId: alice,
      recipientId: alice,
      kind: "sale",
      requestedCopyId: requestedId,
      terms: saleTerms(),
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("SelfExchange");
    expect(events.published).toHaveLength(0);
  });
});

