import { beforeEach, describe, expect, it } from "vitest";
import {
  toCopyId,
  toLoanId,
  toOwnerId,
  toPuzzleDefinitionId,
} from "../../../shared-kernel";
import { CatalogSnapshot, Copy, CopyId, LoanId } from "../../domain";
import {
  FixedClock,
  InMemoryCopyRepository,
  InMemoryLoanRepository,
  RecordingEventPublisher,
  SequentialLoanIdGenerator,
} from "../testing";
import { makeOpenLoan } from "./open-loan";
import { makeRecallLoan } from "./recall-loan";
import { makeReturnLoan } from "./return-loan";

const owner = toOwnerId("alice");
const borrower = toOwnerId("bob");
const definitionId = toPuzzleDefinitionId("def1");
const NOW = new Date("2026-06-08T10:00:00Z");
const LATER = new Date("2026-06-20T10:00:00Z");

const snapshot = (): CatalogSnapshot =>
  CatalogSnapshot.create({
    puzzleDefinitionId: definitionId,
    title: "Owl",
    pieceCount: 500,
  });

describe("loan use cases", () => {
  let copies: InMemoryCopyRepository;
  let loans: InMemoryLoanRepository;
  let events: RecordingEventPublisher;
  let copyId: CopyId;

  beforeEach(async () => {
    copies = new InMemoryCopyRepository();
    loans = new InMemoryLoanRepository();
    events = new RecordingEventPublisher();
    const acquired = Copy.acquire({
      id: toCopyId("copy-seed"),
      ownerId: owner,
      snapshot: snapshot(),
      condition: "good",
      now: NOW,
    });
    if (!acquired.isOk) throw new Error("setup");
    copyId = acquired.value.id;
    await copies.save(acquired.value);
  });

  const open = () =>
    makeOpenLoan({
      copies,
      loans,
      ids: new SequentialLoanIdGenerator(),
      events,
      clock: new FixedClock(NOW),
    });

  describe("makeOpenLoan", () => {
    it("opens a loan, moves possession to the borrower, keeps ownership", async () => {
      const result = await open()({ copyId, borrowerId: borrower });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual(["LoanOpened", "CopyLentOut"]);
      const copy = await copies.findById(copyId);
      expect(copy?.heldBy).toBe(borrower);
      expect(copy?.ownerId).toBe(owner);
    });

    it("rejects an unknown copy", async () => {
      const result = await open()({
        copyId: toCopyId("ghost"),
        borrowerId: borrower,
      });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CopyNotFound");
    });

    it("rejects lending a copy to its own owner (CannotLendToSelf)", async () => {
      const result = await open()({ copyId, borrowerId: owner });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("CannotLendToSelf");
      expect(events.published).toHaveLength(0);
    });
  });

  describe("closing a loan (return / recall)", () => {
    let loanId: LoanId;

    beforeEach(async () => {
      const opened = await open()({ copyId, borrowerId: borrower });
      if (opened.isOk) loanId = opened.value;
    });

    it("the borrower returns the loan -> possession back to the owner", async () => {
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: borrower });
      expect(result.isOk).toBe(true);
      expect((await copies.findById(copyId))?.heldBy).toBe(owner);
      expect(events.names()).toEqual(
        expect.arrayContaining(["LoanClosed", "CopyReturnedToOwner"]),
      );
    });

    it("still closes the loan when the copy no longer exists", async () => {
      await copies.remove(copyId);
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: borrower });
      expect(result.isOk).toBe(true);
      // Exactly the loan close is published — no copy events when the copy is gone.
      expect(events.names()).toEqual([
        "LoanOpened",
        "CopyLentOut",
        "LoanClosed",
      ]);
    });

    it("recall still closes the loan when the copy no longer exists", async () => {
      await copies.remove(copyId);
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: owner });
      expect(result.isOk).toBe(true);
      expect(events.names()).toEqual([
        "LoanOpened",
        "CopyLentOut",
        "LoanClosed",
      ]);
    });

    it("a non-borrower cannot return", async () => {
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: owner });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotBorrower");
    });

    it("the owner recalls the loan -> possession back to the owner", async () => {
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: owner });
      expect(result.isOk).toBe(true);
      expect((await copies.findById(copyId))?.heldBy).toBe(owner);
      expect(events.names()).toEqual(
        expect.arrayContaining(["LoanClosed", "CopyReturnedToOwner"]),
      );
    });

    it("a non-owner cannot recall", async () => {
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId, actingMemberId: borrower });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("NotLender");
    });

    it("rejects closing an unknown loan", async () => {
      const result = await makeReturnLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId: toLoanId("ghost"), actingMemberId: borrower });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("LoanNotFound");
    });

    it("rejects recalling an unknown loan", async () => {
      const result = await makeRecallLoan({
        loans,
        copies,
        events,
        clock: new FixedClock(LATER),
      })({ loanId: toLoanId("ghost"), actingMemberId: owner });
      expect(result.isErr).toBe(true);
      if (result.isErr) expect(result.error.code).toBe("LoanNotFound");
    });
  });
});

src/conversation/domain/thread.spec.ts.source:
import { describe, expect, it } from "vitest";
import {
  toExchangeId,
  toMemberId,
  toMessageId,
  toThreadId,
} from "../../shared-kernel";
import { ExchangeId, MemberId, MessageId, ThreadId } from "./ids";
import { Thread } from "./thread";

const alice = toMemberId("alice");
const bob = toMemberId("bob");
const carol = toMemberId("carol"); // outsider
const exchangeId = toExchangeId("ex-1");
const threadId = toThreadId("thread-1");
const msg1 = toMessageId("message-1");
const msg2 = toMessageId("message-2");
const NOW = new Date("2026-06-08T10:00:00Z");
const LATER = new Date("2026-06-08T11:00:00Z");

const openThread = () => Thread.open(threadId, exchangeId, [alice, bob]);

describe("Thread.postMessage", () => {
  it("appends a participant's text message and records MessagePosted", () => {
    const thread = openThread();

    const result = thread.postMessage({
      id: msg1,
      authorId: alice,
      kind: "text",
      body: "hello bob",
      sentAt: NOW,
    });

    expect(result.isOk).toBe(true);
    if (!result.isOk) return;
    expect(result.value.kind).toBe("text");
    expect(result.value.authorId).toBe(alice);
    expect(thread.messages).toHaveLength(1);

    const events = thread.pullEvents();
    expect(events.map((e) => e.name)).toEqual(["MessagePosted"]);
    const posted = events[0] as unknown as {
      threadId: ThreadId;
      exchangeId: ExchangeId;
      authorId: MemberId | null;
      messageId: MessageId;
      kind: string;
    };
    expect(posted.threadId).toBe(threadId);
    expect(posted.exchangeId).toBe(exchangeId);
    expect(posted.authorId).toBe(alice);
    expect(posted.messageId).toBe(msg1);
    expect(posted.kind).toBe("text");
  });

  it("treats an image body as a storage reference and accepts it", () => {
    const thread = openThread();

    const result = thread.postMessage({
      id: msg1,
      authorId: bob,
      kind: "image",
      body: "storage://abc",
      sentAt: NOW,
    });

    expect(result.isOk).toBe(true);
    if (result.isOk) expect(result.value.kind).toBe("image");
  });

  it("rejects a non-participant author and appends nothing", () => {
    const thread = openThread();

    const result = thread.postMessage({
      id: msg1,
      authorId: carol,
      kind: "text",
      body: "let me in",
      sentAt: NOW,
    });

    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("NotParticipant");
    expect(thread.messages).toHaveLength(0);
    expect(thread.pullEvents()).toHaveLength(0);
  });

  it("rejects an empty body", () => {
    const thread = openThread();

    const result = thread.postMessage({
      id: msg1,
      authorId: alice,
      kind: "text",
      body: "",
      sentAt: NOW,
    });

    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("EmptyMessage");
    expect(thread.messages).toHaveLength(0);
  });

  it("keeps messages in send order", () => {
    const thread = openThread();
    thread.postMessage({
      id: msg1,
      authorId: alice,
      kind: "text",
      body: "first",
      sentAt: NOW,
    });
    thread.postMessage({
      id: msg2,
      authorId: bob,
      kind: "text",
      body: "second",
      sentAt: LATER,
    });

    expect(thread.messages.map((m) => m.id)).toEqual([msg1, msg2]);
  });

  it("drains events only once", () => {
    const thread = openThread();
    thread.postMessage({
      id: msg1,
      authorId: alice,
      kind: "text",
      body: "hi",
      sentAt: NOW,
    });
    expect(thread.pullEvents()).toHaveLength(1);
    expect(thread.pullEvents()).toHaveLength(0);
  });
});

describe("Thread.postSystemMessage", () => {
  it("appends a service-authored system message with no member author", () => {
    const thread = openThread();

    const result = thread.postSystemMessage({
      id: msg1,
      body: "Exchange shipped",
      sentAt: NOW,
    });

    expect(result.isOk).toBe(true);
    if (!result.isOk) return;
    expect(result.value.kind).toBe("system");
    expect(result.value.authorId).toBeNull();

    const posted = thread.pullEvents()[0] as unknown as {
      authorId: MemberId | null;
      kind: string;
    };
    expect(posted.authorId).toBeNull();
    expect(posted.kind).toBe("system");
  });

  it("rejects an empty system body", () => {
    const thread = openThread();
    const result = thread.postSystemMessage({
      id: msg1,
      body: "",
      sentAt: NOW,
    });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("EmptyMessage");
  });
});

describe("Thread.markRead", () => {
  it("records the calling participant's read position", () => {
    const thread = openThread();

    const result = thread.markRead(alice, NOW);

    expect(result.isOk).toBe(true);
    expect(thread.lastReadAt(alice)).toEqual(NOW);
    expect(thread.lastReadAt(bob)).toBeNull();
  });

  it("updates only the caller's receipt, leaving others untouched", () => {
    const thread = openThread();
    thread.markRead(alice, NOW);
    thread.markRead(bob, NOW);

    thread.markRead(alice, LATER);

    expect(thread.lastReadAt(alice)).toEqual(LATER);
    expect(thread.lastReadAt(bob)).toEqual(NOW);
    // One receipt per participant, not a growing log.
    expect(thread.readReceipts).toHaveLength(2);
  });

  it("rejects a non-participant marking read", () => {
    const thread = openThread();
    const result = thread.markRead(carol, NOW);
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("NotParticipant");
    expect(thread.readReceipts).toHaveLength(0);
  });
});

describe("Thread persistence", () => {
  it("round-trips messages and receipts through toState/rehydrate", () => {
    const thread = openThread();
    thread.postMessage({
      id: msg1,
      authorId: alice,
      kind: "text",
      body: "hi",
      sentAt: NOW,
    });
    thread.markRead(bob, NOW);

    const rehydrated = Thread.rehydrate(thread.toState());

    expect(rehydrated.id).toBe(threadId);
    expect(rehydrated.exchangeId).toBe(exchangeId);
    expect(rehydrated.messages.map((m) => m.id)).toEqual([msg1]);
    expect(rehydrated.lastReadAt(bob)).toEqual(NOW);
    // Rehydration does not re-emit events.
    expect(rehydrated.pullEvents()).toHaveLength(0);
  });
});

