import { beforeEach, describe, expect, it } from "vitest";
import { toMemberId } from "../../../shared-kernel";
import { MemberId } from "../../domain";
import {
  FixedClock,
  InMemoryFollowRepository,
  RecordingEventPublisher,
  SequentialFollowIdGenerator,
} from "../testing";
import { makeFollowMember } from "./follow-member";

const alice = toMemberId("alice");
const bob = toMemberId("bob");
const NOW = new Date("2026-06-08T10:00:00Z");

describe("makeFollowMember", () => {
  let follows: InMemoryFollowRepository;
  let events: RecordingEventPublisher;
  let follow: ReturnType<typeof makeFollowMember>;

  beforeEach(() => {
    follows = new InMemoryFollowRepository();
    events = new RecordingEventPublisher();
    follow = makeFollowMember({
      follows,
      followIds: new SequentialFollowIdGenerator(),
      events,
      clock: new FixedClock(NOW),
    });
  });

  it("follows a member: saves the edge and publishes MemberFollowed", async () => {
    const result = await follow({ followerId: alice, followeeId: bob });

    expect(result.isOk).toBe(true);
    expect(follows.size()).toBe(1);
    expect(events.names()).toEqual(["MemberFollowed"]);
    const published = events.published[0] as unknown as {
      followerId: MemberId;
      followeeId: MemberId;
    };
    expect(published.followerId).toBe(alice);
    expect(published.followeeId).toBe(bob);
  });

  it("rejects a self-follow and writes nothing", async () => {
    const result = await follow({ followerId: alice, followeeId: alice });

    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("SelfFollow");
    expect(follows.size()).toBe(0);
    expect(events.published).toHaveLength(0);
  });

  it("rejects a duplicate follow (pair-uniqueness) without writing a second edge", async () => {
    expect((await follow({ followerId: alice, followeeId: bob })).isOk).toBe(
      true,
    );

    const second = await follow({ followerId: alice, followeeId: bob });
    expect(second.isErr).toBe(true);
    if (second.isErr) expect(second.error.code).toBe("AlreadyFollowing");
    expect(follows.size()).toBe(1);
    expect(events.names()).toEqual(["MemberFollowed"]); // only the first
  });

  it("allows a reciprocal follow (distinct direction is a different edge)", async () => {
    expect((await follow({ followerId: alice, followeeId: bob })).isOk).toBe(
      true,
    );

    const back = await follow({ followerId: bob, followeeId: alice });
    expect(back.isOk).toBe(true);
    expect(follows.size()).toBe(2);
  });
});

src/identity/application/use-cases/revok.source:
import { beforeEach, describe, expect, it } from "vitest";
import { toMemberId } from "../../../shared-kernel";
import { Member, MemberId } from "../../domain";
import {
  FixedClock,
  InMemoryMemberRepository,
  RecordingEventPublisher,
} from "../testing";
import { makeAssignRole } from "./assign-role";
import { makeRevokeRole } from "./revoke-role";

const NOW = new Date("2026-06-08T10:00:00Z");
const unknownId = toMemberId("ghost");

const seedMember = (members: InMemoryMemberRepository): MemberId => {
  const result = Member.register({
    id: toMemberId("member-1"),
    clerkId: "clerk_abc",
    email: "alice@example.com",
    name: "Alice",
    now: NOW,
  });
  if (!result.isOk) throw new Error("setup");
  result.value.pullEvents();
  members.save(result.value);
  return result.value.id;
};

describe("makeRevokeRole", () => {
  let members: InMemoryMemberRepository;
  let events: RecordingEventPublisher;
  let assign: ReturnType<typeof makeAssignRole>;
  let revoke: ReturnType<typeof makeRevokeRole>;

  beforeEach(() => {
    members = new InMemoryMemberRepository();
    events = new RecordingEventPublisher();
    assign = makeAssignRole({ members, events, clock: new FixedClock(NOW) });
    revoke = makeRevokeRole({ members, events, clock: new FixedClock(NOW) });
  });

  it("withdraws a held role and publishes RoleRevoked", async () => {
    const id = seedMember(members);
    await assign({ memberId: id, role: "moderator" });
    events.published.length = 0;

    const result = await revoke({ memberId: id, role: "moderator" });
    expect(result.isOk).toBe(true);
    expect((await members.findById(id))?.hasRole("moderator")).toBe(false);
    expect(events.names()).toEqual(["RoleRevoked"]);
  });

  it("is idempotent: revoking an unheld role publishes nothing", async () => {
    const id = seedMember(members);

    const result = await revoke({ memberId: id, role: "admin" });
    expect(result.isOk).toBe(true);
    expect(events.published).toHaveLength(0);
  });

  it("fails with InvalidRole for an unknown role", async () => {
    const id = seedMember(members);
    const result = await revoke({ memberId: id, role: "superuser" });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("InvalidRole");
  });

  it("fails with MemberNotFound for an unknown member", async () => {
    const result = await revoke({ memberId: unknownId, role: "admin" });
    expect(result.isErr).toBe(true);
    if (result.isErr) expect(result.error.code).toBe("MemberNotFound");
  });
});

